  'CendiaWitness': { what:'Immutable evidence chain with legal holds and custody tracking.', does:'Tamper-proof records with legal hold capability. Full chain of custody for every piece of evidence.', usage:'Legal dispute → Witness proves unbroken custody chain → evidence admissible in court → case strengthened.' },
  'CendiaTruth': { what:'Claim verification engine — evidence scoring and fact validation.', does:'Evaluates claims against evidence. Consensus building across multiple sources. Confidence scoring.', usage:'"Is this market report accurate?" → Truth cross-references 12 sources → scores confidence at 87% → flags 2 inconsistencies.' },
  'CendiaMemory': { what:'Institutional memory system — organizational recall across decades.', does:'Knowledge articles, expertise profiles, organizational recall. Prevents institutional amnesia after turnover.', usage:'"Why did we exit the Asian market in 2019?" → Memory recalls: regulatory change + margin pressure + full context preserved.' },

